"use strict";(self.webpackChunkleetcode=self.webpackChunkleetcode||[]).push([[3704],{3342:e=>{e.exports=JSON.parse('{"tag":{"label":"graph","permalink":"/leetcode/es/docs/tags/graph","allTagsPath":"/leetcode/es/docs/tags","count":9,"items":[{"id":"problems/friend-circles","title":"Friend Circles","description":"This question is asked by Facebook. You are given a two dimensional matrix, friends, that represents relationships between coworkers in an office. If friendsi = 1 then coworker i is friends with coworker j and coworker j is friends with coworker i. Similarly if friendsi = 0 then coworker i is not friends with coworker j and coworker j is not friend with coworker i. Friendships in the office are transitive (i.e., if coworker one is friends with coworker two and coworker two is friends with coworker three, coworker one is also friends with coworker three). Given the friendships in the office defined by friends, return the total number of distinct friends groups in the office.","permalink":"/leetcode/es/docs/problems/friend-circles"},{"id":"problems/is-graph-bipartite","title":"Is Graph Bipartite","description":"This question is asked by Facebook. Given an undirected graph, determine whether it is bipartite.","permalink":"/leetcode/es/docs/problems/is-graph-bipartite"},{"id":"problems/keys-and-rooms","title":"Keys and Rooms","description":"This question is asked by Amazon. Given N distinct rooms that are locked, we want to know if you can unlock and visit every room. Each room has a list of keys in it that allows you to unlock and visit other rooms. We start with room 0 being unlocked. Return whether or not we can visit every room.","permalink":"/leetcode/es/docs/problems/keys-and-rooms"},{"id":"problems/largest-pond-size","title":"Largest Pond Size","description":"You are given a two-dimensional matrix that represents a plot of land. Within the matrix there exist two values: ones which represent land and zeroes which represent water within a pond. Given that parts of a pond can be connected both horizontally and vertically (but not diagonally), return the largest pond size.","permalink":"/leetcode/es/docs/problems/largest-pond-size"},{"id":"problems/max-area-of-island","title":"Max Area of Island","description":"Given a 2D array grid, where zeroes represent water and ones represent land, return the size of the largest island.","permalink":"/leetcode/es/docs/problems/max-area-of-island"},{"id":"problems/number-of-islands","title":"Number of Islands","description":"Given a 2D array of integers with ones representing land and zeroes representing water, return the number of islands in the grid.","permalink":"/leetcode/es/docs/problems/number-of-islands"},{"id":"problems/number-of-ships","title":"Number of Ships in Harbor","description":"You\'re about to set sail off a pier and first want to count the number of ships that are already in the harbor. The harbor is deemed safe to sail in if the number of boats in the harbor is strictly less than limit. Given a 2D array that presents the harbor, where O represents water and S represents a ship, return whether or not it\'s safe for you to set sail.","permalink":"/leetcode/es/docs/problems/number-of-ships"},{"id":"problems/rabbit-holes","title":"Rabbit Holes Distance","description":"Given a 2D array containing only the following values: -1, 0, 1 where -1 represents an obstacle, 0 represents a rabbit hole, and 1 represents a rabbit, update every cell containing a rabbit with the distance to its closest rabbit hole.","permalink":"/leetcode/es/docs/problems/rabbit-holes"},{"id":"problems/rotting-oranges","title":"Rotting Oranges (Infection Spread)","description":"Given a 2D array where each cell can have one of three values:","permalink":"/leetcode/es/docs/problems/rotting-oranges"}],"unlisted":false}}')}}]);